// window Onload
window.onload = init;
// MY API KEY
// 4f167c4bc5aba13711a86efc1bd11fe1
// Initialize the Init
function init() {
    // Elements
    var torontoBtn = document.getElementById('Toronto');
    var quebecBtn = document.getElementById('quebec');
    // Functions
    var result = document.getElementById('output');

    // Document Elements for the output result
    var location = document.getElementById('location');
    var icon = document.getElementById('icon');
    var error = document.getElementById('error');
    var temperatures = document.getElementById('temperature');
    var conditions = document.getElementById('conditions');
    var sunset = document.getElementById('sunset');
    // Endpoints
    function API(city) {
        // display the output inline
        result.style.display = 'inline-block';
        const endpoint = `https://api.openweathermap.org/data/2.5/weather?q=${city}&units=metric&appid=4f167c4bc5aba13711a86efc1bd11fe1`;
        // Create XMLHttpRequest Object
        
        var xhr = new XMLHttpRequest();
        // Send the request to end point
        xhr.open('GET', endpoint, true);
        // Request response type JSON
        xhr.responseType = 'json';
        xhr.send(null);
        // Toronto Location Btn
        xhr.onreadystatechange = function () {
            if (xhr.readyState === 4) {
                // Check if response status 200 | 404 | 500 etc..
                if (xhr.status === 200) {
                    var data = xhr.response;
                    console.log(data);
                    // Display the data in the HTML
                    location.innerHTML = data.name;
                    // Display the weather icon
                    icon.innerHTML = `<img src="https://openweathermap.org/img/wn/${data.weather[0].icon}.png" alt="${data.weather[0].description}">`;
                    // Display the temperature, conditions and sunset time
                    temperatures.innerHTML = `${data.main.temp.toFixed(0)}°C`;
                    // Display the weather conditions
                    conditions.innerHTML = `${data.weather[0].description.charAt(0).toUpperCase() + data.weather[0].description.slice(1)}.`;
                    // Display the sunset time
                    sunset.innerHTML = `${new Date(data.sys.sunset * 1000).toLocaleTimeString([], { hour: 'numeric', minute: 'numeric' }).replace(/ AM| PM/, '')} p.m.`;
                }
                // If
                else {
                    error.innerHTML = 'API call was unsuccessful';

                }
            }
        }
    }
    // Initialize with Toronto weather
    API('toronto');

    // Weather API Endpoint
    // Toronto Weather Function
    function torontoWeather() {
        API('toronto');
    }
    // Quebec Weather Function
    function albertaWeather() {
        API('alberta');
    }
    
    // Calling the function on button click
    torontoBtn.onclick = torontoWeather; // Call the function when Toronto Btn is clicked
    quebecBtn.onclick = albertaWeather; // Call the function when Quebec Btn is clicked
}